    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    long long d;
    cin >> n >> d;
    vector<long long> x(n), y(n);
    for (int i = 0; i < n; ++i) cin >> x[i] >> y[i];
    vector<int> infected(n, 0);
    queue<int> q;
    infected[0] = 1;
    q.push(0);
    long long dd = d * d;
    while (!q.empty()) {
        int v = q.front(); q.pop();
        for (int i = 0; i < n; ++i) if (!infected[i]) {
            long long dx = x[v] - x[i], dy = y[v] - y[i];
            if (dx * dx + dy * dy <= dd) {
                infected[i] = 1;
                q.push(i);
            }
        }
    }
    for (int v : infected) cout << (v ? "Yes" : "No") << '\n';
    return 0;
}

