// 参考解：按题意实现核心算法。
bool check(const vector<string> &s, int r, int c) {
    // 左上角 4x4 中 3x3 为黑，其右/下边界为白。
    for (int i = 0; i < 4; ++i) for (int j = 0; j < 4; ++j) {
        char need = (i < 3 && j < 3) ? '#' : '.';
        if (s[r + i][c + j] != need) return false;
    }
    // 右下角同理，坐标平移到 5..8。
    for (int i = 5; i < 9; ++i) for (int j = 5; j < 9; ++j) {
        char need = (i >= 6 && j >= 6) ? '#' : '.';
        if (s[r + i][c + j] != need) return false;
    }
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;
    vector<string> s(n);
    for (auto &row : s) cin >> row;
    for (int i = 0; i + 8 < n; ++i) {
        for (int j = 0; j + 8 < m; ++j) {
            if (check(s, i, j)) cout << i + 1 << ' ' << j + 1 << '\n';
        }
    }
    return 0;
}

