        cin >> a >> b >> c >> d;
        for (int x = a; x < b; ++x) for (int y = c; y < d; ++y) grid[x][y] = 1;
    }
    int ans = 0;
    for (int x = 0; x <= 100; ++x) for (int y = 0; y <= 100; ++y) ans += grid[x][y];
    cout << ans << '\n';
    return 0;
}
